import { Item } from "./types.js";

const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
  sword: { value: 1000, premium: 100 },
  amulet: { value: 600, premium: 60 },
  staff: { value: 800, premium: 80 },
  potion: { value: 400, premium: 40 },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export function isKnownItemType(type: string): boolean {
  return type in MAIN_ITEMS || COMPONENT_TYPES.has(type);
}

export function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

export function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
  if (COMPONENT_TYPES.has(item.type)) return 250;
  throw new Error(`Unknown item type: ${item.type}`);
}

export function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].premium;
  if (COMPONENT_TYPES.has(item.type)) return 25;
  throw new Error(`Unknown item type: ${item.type}`);
}

// Compute base premium for a list of items, applying component block discount.
// Returns the total base premium (sum across all items, with block discounts for components).
export function computePolicyBasePremium(items: Item[]): number {
  let total = 0;
  // group components by type to apply block discount
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else if (item.type in MAIN_ITEMS) {
      total += MAIN_ITEMS[item.type].premium;
    } else {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  for (const [, count] of componentCounts) {
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    total += blocks * 60 + remainder * 25;
  }
  return total;
}

// Compute the per-item premium contribution including item-specific modifiers (cursed, high enchantment).
// Components do NOT receive per-item modifiers (they have no enchantment/cursed in spec scope).
// Returns fractional total of (item base premium + item surcharges) summed across all items.
export function computeItemContributionsWithSurcharges(items: Item[]): number {
  let total = 0;
  // First, sum main item base + surcharges per item.
  for (const item of items) {
    if (item.type in MAIN_ITEMS) {
      const base = MAIN_ITEMS[item.type].premium;
      let itemTotal = base;
      if (item.cursed) itemTotal += base * 0.5;
      if ((item.enchantment ?? 0) >= 5) itemTotal += base * 0.3;
      total += itemTotal;
    }
  }
  // Then handle components with block logic, no per-item surcharges
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else if (!(item.type in MAIN_ITEMS)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  for (const [, count] of componentCounts) {
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    total += blocks * 60 + remainder * 25;
  }
  return total;
}

export interface QuoteContext {
  yearsWithMHPCO: number;
  isFollowUpContract: boolean; // true if this is not the customer's first quote
}

export function computePremium(items: Item[], ctx: QuoteContext): number {
  // Validate item types first
  for (const item of items) {
    if (!isKnownItemType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  if (items.length === 0) {
    return 5;
  }

  // Per spec: item-specific surcharges (cursed, high enchantment) apply to that item's base premium;
  // policy-wide modifiers (loyalty, first insurance, follow-up) apply to the policy base premium
  // (sum of item base premiums). Each item in a quote is treated as a first insurance.
  const policyBase = computePolicyBasePremium(items);

  // Item-level surcharges
  let itemSurcharges = 0;
  for (const item of items) {
    if (item.type in MAIN_ITEMS) {
      const base = MAIN_ITEMS[item.type].premium;
      if (item.cursed) itemSurcharges += base * 0.5;
      if ((item.enchantment ?? 0) >= 5) itemSurcharges += base * 0.3;
    }
  }

  // Policy-wide modifiers: loyalty, first insurance, follow-up
  let policyAdjustments = 0;
  if (ctx.yearsWithMHPCO >= 2) {
    policyAdjustments -= policyBase * 0.2;
  }
  // First insurance: 10% surcharge — applies to every item being insured (each item is a first insurance)
  policyAdjustments += policyBase * 0.1;
  // Follow-up contract: 15% discount applies if this isn't customer's first contract
  if (ctx.isFollowUpContract) {
    policyAdjustments -= policyBase * 0.15;
  }

  const total = policyBase + itemSurcharges + policyAdjustments + 5;

  // Round up (in MHPCO's favor for premium)
  return Math.ceil(total);
}

export function computeInsuranceSum(items: Item[]): number {
  let sum = 0;
  for (const item of items) {
    sum += itemInsuranceValue(item);
  }
  return sum;
}

