});

describe("Claim: Multiple items of the same type (clarifying ❓)", () => {
  it("two swords: insurance sum 2000, cap 4000", () => {
    const scenario: Scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }, { type: "sword" }] },
