import { Damage, Item, Policy } from "./types.js";
import { isKnownItemType } from "./pricing.js";

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

// Validate damages: every itemType must be known, every damage must reference an item present in the policy.
// We match damages to items by type. If the damages array contains more entries of a given type than
// the policy actually covers, throw.
// Also: damage amount must be non-negative.
export function processClaim(policy: Policy, damages: Damage[]): ClaimResult {
  // Validation
  for (const dmg of damages) {
    if (!isKnownItemType(dmg.itemType)) {
      throw new Error(`Unknown item type in claim: ${dmg.itemType}`);
    }
    if (dmg.amount < 0) {
      throw new Error(`Damage amount must be non-negative, got ${dmg.amount}`);
    }
  }

  // Count items in policy by type
  const policyTypeCounts = new Map<string, number>();
  for (const item of policy.items) {
    policyTypeCounts.set(item.type, (policyTypeCounts.get(item.type) ?? 0) + 1);
  }

  // Count damages by type, ensure each does not exceed policy items
  const damageTypeCounts = new Map<string, number>();
  for (const dmg of damages) {
    damageTypeCounts.set(dmg.itemType, (damageTypeCounts.get(dmg.itemType) ?? 0) + 1);
  }
  for (const [type, count] of damageTypeCounts) {
    const available = policyTypeCounts.get(type) ?? 0;
    if (count > available) {
      throw new Error(
        `Claim references more ${type} damages (${count}) than policy covers (${available})`
      );
    }
  }

  // Now, for each damage, find a matching item from the policy (consume one per damage).
  // To get correct item attributes (material, enchantment), we keep a list of available items per type.
  const availableByType = new Map<string, Item[]>();
  for (const item of policy.items) {
    if (!availableByType.has(item.type)) availableByType.set(item.type, []);
    availableByType.get(item.type)!.push(item);
  }

  let totalPayout = 0;
  for (const dmg of damages) {
    const available = availableByType.get(dmg.itemType);
    if (!available || available.length === 0) {
      throw new Error(`No remaining ${dmg.itemType} item in policy for damage`);
    }
    // Pick the first available item of this type (consume one).
    const item = available.shift()!;

    let reimburse = dmg.amount;
    const isDragon = item.material === "dragon";
    const isHighEnchantment = (item.enchantment ?? 0) >= 8;

    // Per spec: dragon-material fully reimbursed; high-enchantment 50%.
    // When both clauses apply, the 50% rule wins (from the "enchantment 9 + dragon" example).
    if (isHighEnchantment) {
      reimburse = reimburse * 0.5;
    }
    // dragon material: full reimbursement (i.e. no reduction beyond what we may have from enchantment? Re-read spec.)
    // Re-checking: "dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both apply; 50% wins, then deductible)"
    // So when both apply, only 50% — dragon does not override.
    // "dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only the dragon-material clause applies)"
    // Dragon just means "full reimbursement" — i.e., no reduction (which is the default).
    // So dragon doesn't actually change anything beyond defaults? It just means high-enchantment doesn't *not* apply?
    // Re-reading: "Damage to items with enchantment level ≥ 8 is reimbursed at 50%."
    // "Damage to items made of dragon material is fully reimbursed."
    // Both rules independent. The first reduces, the second confirms full. When both apply, 50% wins per example.
    // So dragon is a no-op overlay on the default; only relevant in that high-ench would still apply when both.
    // My current logic only applies the 50% reduction when ench>=8; dragon does nothing. That matches all examples.

    // Apply deductible per damage event
    reimburse = reimburse - 100;
    if (reimburse < 0) reimburse = 0;

    totalPayout += reimburse;
  }

  // Cap remaining
  let payout = totalPayout;
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }

  // Round payout down (in MHPCO's favor)
  payout = Math.floor(payout);

  policy.remainingCap = policy.remainingCap - payout;

  return { payout, remainingCap: policy.remainingCap };
}

