import { Scenario, Output, Policy, StepResult } from "./types.js";
import { computePremium, computeInsuranceSum, isKnownItemType } from "./pricing.js";
import { processClaim } from "./claim.js";

export function runScenario(scenario: Scenario): Output {
  const results: StepResult[] = [];
  const policies = new Map<number, Policy>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      // Validate all items
      for (const item of step.items) {
        if (!isKnownItemType(item.type)) {
          throw new Error(`Unknown item type: ${item.type}`);
        }
      }
      const isFollowUpContract = quoteCount > 0;
      const premium = computePremium(step.items, {
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        isFollowUpContract,
      });
      quoteCount++;
      const insuranceSum = computeInsuranceSum(step.items);
      const policy: Policy = {
        items: step.items,
        insuranceSum,
        cap: insuranceSum * 2,
        remainingCap: insuranceSum * 2,
      };
      policies.set(i, policy);
      results.push({ premium });
    } else if (step.op === "claim") {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy index ${step.policy}`);
      }
      const result = processClaim(policy, step.incident.damages);
      results.push(result);
    } else {
      throw new Error(`Unknown op: ${(step as { op: string }).op}`);
    }
  }

  return { results };
}
